48	/** Kit contribution interface for the Clerk's writ type system. */
49	export interface ClerkKit {
50	  /** Writ type descriptors to register with the Clerk. Names are unqualified. */
51	  writTypes?: WritTypeEntry[];
52	}
53	
54	// ── Built-in writ types ──────────────────────────────────────────────
55	
56	const BUILTIN_TYPES = new Set(['mandate']);
57	
58	// ── Status machine ───────────────────────────────────────────────────
59	
60	const ALLOWED_FROM: Record<WritStatus, WritStatus[]> = {
61	  ready: ['new'],
62	  active: ['ready'],
63	  completed: ['active'],
64	  failed: ['active'],
65	  cancelled: ['new', 'ready', 'active'],
66	  new: [],
67	};
68	
69	const TERMINAL_STATUSES = new Set<WritStatus>(['completed', 'failed', 'cancelled']);
70	
71	// ── Factory ──────────────────────────────────────────────────────────
72	
73	export function createClerk(): Plugin {
74	  let writs: Book<WritDoc>;
75	  let links: Book<WritLinkDoc>;
76	
77	  /** Merged set of valid writ type names: builtins + config + kit contributions. */
78	  let mergedWritTypes: Set<string> = new Set(BUILTIN_TYPES);
79	
80	  /** Config-declared writ type names, for override checking during kit registration. */
81	  let configWritTypeNames: Set<string> = new Set();
82	
83	  // ── Helpers ──────────────────────────────────────────────────────
84	
85	  function resolveClerkConfig(): ClerkConfig {
86	    return guild().guildConfig().clerk ?? {};
87	  }
88	
89	  function resolveWritTypes(): Set<string> {
90	    return mergedWritTypes;
91	  }
92	
93	  function resolveDefaultType(): string {
94	    const config = resolveClerkConfig();
95	    return config.defaultType ?? 'mandate';
96	  }
97	
98	  function buildWhereClause(filters?: WritFilters): WhereClause | undefined {
99	    const conditions: WhereClause = [];
100	    if (filters?.status) {
101	      conditions.push(['status', '=', filters.status]);
102	    }
103	    if (filters?.type) {
104	      conditions.push(['type', '=', filters.type]);
105	    }
106	    return conditions.length > 0 ? conditions : undefined;
107	  }
108	
109	  function registerKitWritTypes(kitEntry: { pluginId: string; value: unknown }): void {
110	    const pluginId = kitEntry.pluginId;
111	    const raw = kitEntry.value;
112	    if (!Array.isArray(raw)) return;
113	
114	    for (const entry of raw) {
115	      if (
116	        typeof entry !== 'object' ||
117	        entry === null ||
118	        typeof (entry as Record<string, unknown>).name !== 'string'
119	      ) {
120	        console.warn(
121	          `[clerk] Kit "${pluginId}" writTypes: entry is missing required "name" field — skipped`
122	        );
123	        continue;
124	      }
125	      const name = (entry as WritTypeEntry).name;
126	
127	      // Config override: skip silently
128	      if (configWritTypeNames.has(name)) continue;
129	
130	      // Duplicate kit contribution: first wins, warn
131	      if (mergedWritTypes.has(name)) {
132	        console.warn(
133	          `[clerk] Kit "${pluginId}" writTypes: type "${name}" already registered by another kit — skipped`
134	        );
135	        continue;
136	      }
137	
138	      mergedWritTypes.add(name);
139	    }
140	  }
141	
142	  // ── API ──────────────────────────────────────────────────────────
143	
144	  const api: ClerkApi = {
145	    async post(request: PostCommissionRequest): Promise<WritDoc> {
146	      const type = request.type ?? resolveDefaultType();
147	      const validTypes = resolveWritTypes();
148	
149	      if (!validTypes.has(type)) {
150	        throw new Error(
151	          `Unknown writ type "${type}". Declared types: ${[...validTypes].join(', ')}.`,
152	        );
153	      }
154	
155	      const now = new Date().toISOString();
156	      const writ: WritDoc = {
157	        id: generateId('w', 6),
158	        type,
159	        status: request.draft === true ? 'new' : 'ready',
160	        title: request.title,
161	        body: request.body,
162	        ...(request.codex !== undefined ? { codex: request.codex } : {}),
163	        createdAt: now,
164	        updatedAt: now,
165	      };
166	
167	      await writs.put(writ);
168	      return writ;
