288	    handler: async () => {
289	      const config = resolveClerkConfig();
290	      const defaultType = resolveDefaultType();
291	      const configEntries = config.writTypes ?? [];
292	
293	      return [...mergedWritTypes].map((name) => {
294	        const entry = configEntries.find((e) => e.name === name);
295	        return {
296	          name,
297	          description: entry?.description ?? null,
298	          default: name === defaultType,
299	        };
300	      });
301	    },
302	  });
303	
304	  // ── Apparatus ────────────────────────────────────────────────────
305	
306	  return {
307	    apparatus: {
308	      requires: ['stacks'],
309	      recommends: ['oculus'],
310	      consumes: ['writTypes'],
311	
312	      supportKit: {
313	        books: {
314	          writs: {
315	            indexes: ['status', 'type', 'createdAt', ['status', 'type'], ['status', 'createdAt']],
316	          },
317	          links: {
318	            indexes: ['sourceId', 'targetId', 'type', ['sourceId', 'type'], ['targetId', 'type']],
319	          },
320	        },
321	        tools: [
322	          commissionPost,
323	          writShow,
324	          writList,
325	          writAccept,
326	          writComplete,
327	          writFail,
328	          writCancel,
329	          writPublish,
330	          writLink,
331	          writUnlink,
332	          writTypesTool,
333	        ],
334	        pages: [
335	          { id: 'writs', title: 'Writs', dir: 'pages/writs' },
336	        ],
337	      },
338	
339	      provides: api,
340	
341	      start(ctx: StartupContext): void {
342	        const g = guild();
343	        const stacks = g.apparatus<StacksApi>('stacks');
344	        writs = stacks.book<WritDoc>('clerk', 'writs');
345	        links = stacks.book<WritLinkDoc>('clerk', 'links');
346	
347	        // Initialize merged writ types from builtins + config
348	        const config = resolveClerkConfig();
349	        configWritTypeNames = new Set((config.writTypes ?? []).map((e) => e.name));
350	        mergedWritTypes = new Set([...BUILTIN_TYPES, ...configWritTypeNames]);
351	
352	        // Scan all kit-contributed writ types via the Wire-phase snapshot.
353	        for (const entry of ctx.kits('writTypes')) {
354	          registerKitWritTypes(entry);
355	        }
356	      },
357	    },
358	  };
359	}
