1	/**
2	 * The Spider — public types.
3	 *
4	 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5	 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6	 * packages can import them without depending on the engine implementation files.
7	 */
8	
9	import type { ZodSchema } from 'zod';
10	
11	// ── Engine instance status ────────────────────────────────────────────
12	
13	export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked' | 'skipped';
14	
15	// ── Block record ──────────────────────────────────────────────────────
16	
17	/**
18	 * Persisted record of an active engine block.
19	 * Present on an EngineInstance when status === 'blocked'.
20	 * Cleared when the block is resolved.
21	 */
22	export interface BlockRecord {
23	  /** Block type identifier (matches a registered BlockType.id). */
24	  type: string;
25	  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26	  condition: unknown;
27	  /** ISO timestamp when the engine was blocked. */
28	  blockedAt: string;
29	  /** Optional human-readable message from the engine. */
30	  message?: string;
31	  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32	  lastCheckedAt?: string;
33	}
34	
35	// ── Engine instance ───────────────────────────────────────────────────
36	
37	/**
38	 * A single engine slot within a rig.
39	 *
40	 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41	 * For the static pipeline it matches `designId`.
42	 *
43	 * `givensSpec` holds values set at spawn time (writ, role, commands) and
44	 * may contain unresolved yield reference strings ('$yields.<id>.<prop>')
45	 * that the Spider resolves at run time from upstream engine yields.
46	 */
47	export interface EngineInstance {
48	  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49	  id: string;
50	  /** The engine design to look up in the Fabricator. */
51	  designId: string;
52	  /** Current execution status. */
53	  status: EngineStatus;
54	  /** Engine IDs that must be completed before this engine can run. */
55	  upstream: string[];
56	  /**
57	   * Givens values. Spawn-time references ($writ, $vars.*) are resolved to
58	   * their values. Yield references ($yields.*.*) remain as strings and are
59	   * resolved at run time when the engine is executed.
60	   */
61	  givensSpec: Record<string, unknown>;
62	  /**
63	   * Conditional activation expression, copied from the template.
64	   * Evaluated at runtime when upstream is all done. Absent means unconditional.
65	   */
66	  when?: string;
67	  /** Yields from a completed engine run (JSON-serializable). */
68	  yields?: unknown;
69	  /** Error message if this engine failed. */
70	  error?: string;
71	  /** Session ID from a launched quick engine, used by the collect step. */
72	  sessionId?: string;
73	  /** ISO timestamp when execution started. */
74	  startedAt?: string;
75	  /** ISO timestamp when execution completed (or failed). */
76	  completedAt?: string;
77	  /** Present when status === 'blocked'. Cleared when the block is resolved. */
78	  block?: BlockRecord;
79	}
80	
81	// ── Rig ──────────────────────────────────────────────────────────────
82	
83	export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
84	
85	/**
86	 * A rig — the execution context for a single writ.
87	 *
88	 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
89	 * ordered pipeline of engine instances. The Spider updates this document
90	 * in-place as engines run and complete.
91	 */
92	export interface RigDoc {
93	  /** Index signature required to satisfy BookEntry constraint. */
94	  [key: string]: unknown;
95	  /** Unique rig id. */
96	  id: string;
97	  /** The writ this rig is executing. */
98	  writId: string;
99	  /** Current rig status. */
100	  status: RigStatus;
101	  /** Ordered engine pipeline. */
102	  engines: EngineInstance[];
103	  /** ISO timestamp when the rig was created. */
104	  createdAt: string;
105	  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
106	  resolutionEngineId?: string;
107	}
108	
109	// ── Rig filters ───────────────────────────────────────────────────────
110	
111	/**
112	 * Filters for listing rigs.
113	 */
114	export interface RigFilters {
115	  /** Filter by rig status. */
116	  status?: RigStatus;
117	  /** Maximum number of results (default: 20). */
118	  limit?: number;
119	  /** Number of results to skip. */
120	  offset?: number;
121	}
122	
123	// ── Rig templates ─────────────────────────────────────────────────────
124	
125	/**
126	 * A single engine slot declared in a rig template.
127	 */
128	export interface RigTemplateEngine {
129	  /** Engine id unique within this template. */
130	  id: string;
131	  /** Engine design id to look up in the Fabricator. */
132	  designId: string;
133	  /** Engine ids within this template whose completion is required first. Defaults to []. */
134	  upstream?: string[];
135	  /**
136	   * Givens to pass to the engine.
137	   * String values starting with '$' (either $name or ${name}) are variable
138	   * references:
139	   *   '$writ' or '${writ}' — the WritDoc for this rig's writ
140	   *   '$vars.<key>' or '${vars.<key>}' — value from spider.variables config
141	   *   '$yields.<engine_id>.<property>' or '${yields.<engine_id>.<property>}'
142	   *       — a property from an upstream engine's yields (resolved at run time)
143	   * Non-string values are passed through literally.
144	   * Variables that resolve to undefined cause the key to be omitted.
145	   */
146	  givens?: Record<string, unknown>;
147	  /**
148	   * Conditional activation expression. A `$yields.<engine_id>.<property>` reference
149	   * (with optional `!` negation prefix) evaluated at runtime when the engine's upstream
150	   * is all done. When the condition is falsy, the engine is set to `skipped` status.
151	   * When absent, the engine is unconditional (always runs).
152	   *
153	   * Examples:
154	   *   '$yields.review.passed'    — run this engine when review.passed is truthy
155	   *   '!$yields.review.passed'   — run this engine when review.passed is falsy
156	   *   '${yields.review.passed}'  — equivalent (curly-brace syntax)
157	   *   '!${yields.review.passed}' — equivalent negated
158	   */
159	  when?: string;
160	}
161	
162	/**
163	 * A complete rig template.
164	 */
165	export interface RigTemplate {
166	  /** Ordered list of engine slot declarations. */
167	  engines: RigTemplateEngine[];
168	  /**
169	   * Engine id whose yields provide the writ resolution summary.
170	   * Falls back to seal engine, then last completed engine in array order.
171	   */
172	  resolutionEngine?: string;
173	}
174	
175	// ── CrawlResult ────────────────────────────────────────────────────────
176	
177	/**
178	 * The result of a single crawl() call.
179	 *
180	 * Variants, ordered by priority:
181	 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
182	 * - 'engine-started'    — launched a quick engine's session
183	 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
184	 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
185	 * - 'rig-spawned'       — created a new rig for a ready writ
186	 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
187	 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
188	 *
189	 * null means no work was available.
190	 */
191	export type CrawlResult =
192	  | { action: 'engine-completed'; rigId: string; engineId: string }
193	  | { action: 'engine-started'; rigId: string; engineId: string }
194	  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
195	  | { action: 'engine-unblocked'; rigId: string; engineId: string }
196	  | { action: 'engine-skipped'; rigId: string; engineId: string; cascadeSkipped?: string[] }
197	  | { action: 'engine-grafted'; rigId: string; engineId: string; graftedEngineIds: string[] }
198	  | { action: 'rig-spawned'; rigId: string; writId: string }
199	  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
200	  | { action: 'rig-blocked'; rigId: string; writId: string };
201	
202	// ── Block type ────────────────────────────────────────────────────────
203	
204	/**
205	 * Result of a block type check.
206	 *
207	 * 'cleared' — condition met, unblock the engine.
208	 * 'pending' — condition not yet met, keep polling.
209	 * 'failed'  — condition is permanently unresolvable, fail the engine.
210	 *
211	 * When status is 'failed', an optional reason provides a human-readable
212	 * explanation that the Spider includes in the engine error message.
213	 */
214	export interface CheckResult {
215	  status: 'cleared' | 'pending' | 'failed';
216	  reason?: string;
217	}
218	
219	/** Summary info for a registered block type. */
220	export interface BlockTypeInfo {
221	  /** Block type id. */
222	  id: string;
223	  /** Plugin id that contributed this block type. */
224	  pluginId: string;
225	  /** Suggested poll interval in milliseconds, if set. */
226	  pollIntervalMs?: number;
227	}
228	
229	/** Summary info for a registered rig template. */
230	export interface RigTemplateInfo {
231	  /** Template name (plain for config, qualified pluginId.name for kit). */
232	  name: string;
233	  /** 'config' for guild.json templates, or the pluginId for kit-contributed templates. */
234	  source: string;
235	  /** The template definition. */
236	  template: RigTemplate;
237	}
238	
239	/**
240	 * A registered block type — defines how to check whether a blocking
241	 * condition has cleared. Contributed via kit/supportKit `blockTypes`.
242	 */
243	export interface BlockType {
244	  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
245	  id: string;
246	  /**
247	   * Check whether the blocking condition has been resolved.
248	   *
249	   * Return { status: 'cleared' } when the condition is met.
250	   * Return { status: 'pending' } when the condition is not yet met.
251	   * Return { status: 'failed' } or { status: 'failed', reason: '...' }
252	   * when the condition is permanently unresolvable.
253	   *
254	   * Throwing is reserved for transient errors (network failures, etc.)
255	   * — the engine stays blocked and the checker is retried next cycle.
256	   */
257	  check: (condition: unknown) => Promise<CheckResult>;
258	  /** Zod schema for validating the condition payload at block time. */
259	  conditionSchema: ZodSchema;
260	  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
261	  pollIntervalMs?: number;
262	}
263	
264	// ── SpiderApi ─────────────────────────────────────────────────────────
265	
266	/**
267	 * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
268	 */
269	export interface SpiderApi {
270	  /**
271	   * Execute one step of the crawl loop.
272	   *
273	   * Priority ordering: collect > checkBlocked > run > spawn.
274	   * Returns null when no work is available.
275	   */
276	  crawl(): Promise<CrawlResult | null>;
277	
278	  /**
279	   * Show a rig by id. Throws if not found.
280	   */
281	  show(id: string): Promise<RigDoc>;
282	
283	  /**
284	   * List rigs with optional filters, ordered by createdAt descending.
285	   */
286	  list(filters?: RigFilters): Promise<RigDoc[]>;
287	
288	  /**
289	   * Find the rig for a given writ. Returns null if no rig exists.
290	   */
291	  forWrit(writId: string): Promise<RigDoc | null>;
292	
293	  /**
294	   * Manually clear a block on a specific engine, regardless of checker result.
295	   * Throws if the engine is not blocked.
296	   */
297	  resume(rigId: string, engineId: string): Promise<void>;
298	
299	  /**
300	   * Look up a registered block type by ID.
301	   */
302	  getBlockType(id: string): BlockType | undefined;
303	
304	  /**
305	   * List all registered block types with summary info.
306	   */
307	  listBlockTypes(): BlockTypeInfo[];
308	
309	  /**
310	   * List all registered rig templates with provenance info.
311	   */
312	  listTemplates(): RigTemplateInfo[];
313	
314	  /**
315	   * Return the merged effective writ-type → template-name mapping.
316	   * Config mappings override kit mappings for the same writ type.
317	   */
318	  listTemplateMappings(): Record<string, string>;
319	}
320	
321	// ── Configuration ─────────────────────────────────────────────────────
322	
323	/**
324	 * Spider apparatus configuration — lives under the `spider` key in guild.json.
325	 */
326	export interface SpiderConfig {
327	  /**
328	   * Polling interval for crawlContinual tool (milliseconds).
329	   * Default: 5000.
330	   */
331	  pollIntervalMs?: number;
332	  /**
333	   * Build command to pass to quick engines.
334	   */
335	  buildCommand?: string;
336	  /**
337	   * Test command to pass to quick engines.
338	   */
339	  testCommand?: string;
340	  /**
341	   * Named rig templates. Keys are template names (not writ types).
342	   * Templates are looked up by name via rigTemplateMappings.
343	   * A template named 'default' is used as the fallback when no mapping matches.
344	   */
345	  rigTemplates?: Record<string, RigTemplate>;
346	  /**
347	   * Writ type → rig template name mappings.
348	   * 'default' key is the fallback for unmatched writ types.
349	   * Config mappings override kit-contributed mappings for the same writ type.
350	   */
351	  rigTemplateMappings?: Record<string, string>;
352	  /**
353	   * User-defined variables available in rig template givens via '$vars.<key>'.
354	   * Values are passed through literally (string, number, boolean).
355	   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
356	   */
357	  variables?: Record<string, unknown>;
358	  /**
359	   * Maximum number of engines allowed in a single rig.
360	   * Grafts that would exceed this limit fail the originating engine.
361	   * Default: 50.
362	   */
363	  maxEnginesPerRig?: number;
364	}
365	
366	// ── Engine yield shapes ───────────────────────────────────────────────
367	
368	/**
369	 * Yields from the `draft` clockwork engine.
370	 * The Spider stores these in the engine instance and passes them
371	 * to downstream engines via context.upstream['draft'].
372	 */
373	export interface DraftYields {
374	  /** The draft's unique id. */
375	  draftId: string;
376	  /** Codex this draft belongs to. */
377	  codexName: string;
378	  /** Git branch name for the draft. */
379	  branch: string;
380	  /** Absolute filesystem path to the draft's worktree. */
381	  path: string;
382	  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
383	  baseSha: string;
384	}
385	
386	/**
387	 * Yields from the `seal` clockwork engine.
388	 */
389	export interface SealYields {
390	  /** The commit SHA at head of the target branch after sealing. */
391	  sealedCommit: string;
392	  /** Git strategy used. */
393	  strategy: 'fast-forward' | 'rebase';
394	  /** Number of retry attempts. */
395	  retries: number;
396	  /** Number of inscriptions (commits) sealed. */
397	  inscriptionsSealed: number;
398	}
399	
400	/**
401	 * Yields from the `implement` quick engine.
402	 * Set by the Spider's collect step when the Animator session completes.
403	 */
404	export interface ImplementYields {
405	  /** The Animator session id. */
406	  sessionId: string;
407	  /** Terminal status of the session. */
408	  sessionStatus: 'completed' | 'failed';
409	}
410	
411	/**
412	 * A single mechanical check (build or test) run by the review engine
413	 * before launching the reviewer session.
414	 */
415	export interface MechanicalCheck {
416	  /** Check name. */
417	  name: 'build' | 'test';
418	  /** Whether the command exited with code 0. */
419	  passed: boolean;
420	  /** Combined stdout+stderr, truncated to 4KB. */
421	  output: string;
422	  /** Wall-clock duration of the check in milliseconds. */
423	  durationMs: number;
424	}
425	
426	/**
427	 * Yields from the `review` quick engine.
428	 * Assembled by the Spider's collect step from session.output and session.metadata.
429	 */
430	export interface ReviewYields {
431	  /** The Animator session id. */
432	  sessionId: string;
433	  /** Reviewer's overall assessment — true if the review passed. */
434	  passed: boolean;
435	  /** Structured markdown findings from the reviewer's final message. */
436	  findings: string;
437	  /** Mechanical check results run before the reviewer session. */
438	  mechanicalChecks: MechanicalCheck[];
439	}
440	
441	/**
442	 * Yields from the `revise` quick engine.
443	 * Set by the Spider's collect step when the Animator session completes.
444	 */
445	export interface ReviseYields {
446	  /** The Animator session id. */
447	  sessionId: string;
448	  /** Terminal status of the session. */
449	  sessionStatus: 'completed' | 'failed';
450	}
451	
452	// ── Input request types ──────────────────────────────────────────────
453	
454	export type InputRequestStatus = 'pending' | 'completed' | 'rejected';
455	
456	export interface ChoiceQuestionSpec {
457	  type: 'choice';
458	  /** Human-readable question text. */
459	  label: string;
460	  /** Optional long-form context, explanation, or instructions for this question. */
461	  details?: string;
462	  /** Key → display label options map. */
463	  options: Record<string, string>;
464	  /** When true, the patron can supply a freeform answer instead of selecting. */
465	  allowCustom: boolean;
466	}
467	
468	export interface BooleanQuestionSpec {
469	  type: 'boolean';
470	  /** Human-readable question text. */
471	  label: string;
472	  /** Optional long-form context, explanation, or instructions for this question. */
473	  details?: string;
474	}
475	
476	export interface TextQuestionSpec {
477	  type: 'text';
478	  /** Human-readable question text. */
479	  label: string;
480	  /** Optional long-form context, explanation, or instructions for this question. */
481	  details?: string;
482	}
483	
484	export type QuestionSpec = ChoiceQuestionSpec | BooleanQuestionSpec | TextQuestionSpec;
485	
486	/** Discriminated choice answer — selected from options or freeform custom. */
487	export type ChoiceAnswer = { selected: string } | { custom: string };
488	
489	/**
490	 * Answer value union. Runtime type is determined by the corresponding QuestionSpec:
491	 * - choice → ChoiceAnswer (object with 'selected' or 'custom' key)
492	 * - boolean → boolean
493	 * - text → string
494	 */
495	export type AnswerValue = ChoiceAnswer | boolean | string;
496	
497	/**
498	 * An input request document stored in the spider/input-requests book.
499	 * Created by engines before blocking; answered by patrons via CLI tools.
500	 */
501	export interface InputRequestDoc {
502	  [key: string]: unknown;
503	  /** Unique ID via generateId('ir', 4). */
504	  id: string;
505	  /** Rig this request belongs to. */
506	  rigId: string;
507	  /** Engine that created this request. */
508	  engineId: string;
509	  /** Request lifecycle status. */
510	  status: InputRequestStatus;
511	  /** Optional human-readable context from the engine. */
512	  message?: string;
513	  /** Question key → question spec. */
514	  questions: Record<string, QuestionSpec>;
515	  /** Question key → answer value. Partially filled until completion. */
516	  answers: Record<string, AnswerValue>;
517	  /** Set when status transitions to 'rejected'. */
518	  rejectionReason?: string;
519	  /** ISO timestamp when the request was created. */
520	  createdAt: string;
521	  /** ISO timestamp of the last mutation. */
522	  updatedAt: string;
523	}
524	
525	// ── Spider-extended engine run / collect result types ─────────────────
526	
527	/**
528	 * Spider-extended engine run result. Adds an optional `graft` field
529	 * to the `completed` variant, allowing engines to dynamically append
530	 * new engines to the rig alongside their yields.
531	 *
532	 * Engines that want to graft import this type from @shardworks/spider-apparatus.
533	 * Engines that don't graft use the base EngineRunResult from @shardworks/fabricator-apparatus.
534	 *
535	 * The Spider internally checks for the `graft` property on any completed result
536	 * (duck-typing — the Fabricator type is not modified).
537	 */
538	export type SpiderEngineRunResult =
539	  | { status: 'completed'; yields: unknown; graft?: RigTemplateEngine[] }
540	  | { status: 'launched'; sessionId: string }
541	  | { status: 'blocked'; blockType: string; condition: unknown; message?: string };
542	
543	/**
544	 * Spider-extended collect result. When a quick engine's collect() method
545	 * returns an object with a `graft` property (an array), the Spider extracts
546	 * it as a graft request and uses the `yields` property as the engine's yields.
547	 *
548	 * When collect() returns a value without a `graft` array property, the entire
549	 * return value is treated as yields (backward compatible).
550	 */
551	export interface SpiderCollectResult {
552	  yields: unknown;
553	  graft?: RigTemplateEngine[];
554	}
555	
556	// Augment GuildConfig so `guild().guildConfig().spider` is typed.
557	declare module '@shardworks/nexus-core' {
558	  interface GuildConfig {
