29	  RigDoc,
30	  RigFilters,
31	  EngineInstance,
32	  SpiderApi,
33	  CrawlResult,
34	  SpiderConfig,
35	  BlockRecord,
36	  BlockType,
37	  BlockTypeInfo,
38	  CheckResult,
39	  RigTemplate,
40	  RigTemplateEngine,
41	  RigTemplateInfo,
42	  SpiderCollectResult,
43	} from './types.ts';
44	
45	import {
46	  animaSessionEngine,
47	  draftEngine,
48	  implementEngine,
49	  reviewEngine,
50	  reviseEngine,
51	  sealEngine,
52	} from './engines/index.ts';
53	
54	import {
55	  writStatusBlockType,
56	  scheduledTimeBlockType,
57	  bookUpdatedBlockType,
58	  patronInputBlockType,
59	} from './block-types/index.ts';
60	
61	import {
62	  crawlOneTool,
63	  crawlContinualTool,
64	  rigShowTool,
65	  rigListTool,
66	  rigForWritTool,
67	  rigResumeTool,
68	  inputRequestListTool,
69	  inputRequestShowTool,
70	  inputRequestAnswerTool,
71	  inputRequestCompleteTool,
72	  inputRequestRejectTool,
73	  inputRequestExportTool,
74	  inputRequestImportTool,
75	  engineDesignsTool,
76	  blockTypesTool,
77	} from './tools/index.ts';
78	
79	import { spiderRoutes } from './oculus-routes.ts';
80	
81	// ── Kit contribution interface ─────────────────────────────────────────
82	
83	/** Kit contribution interface for the Spider's rig template system. */
84	export interface SpiderKit {
85	  /** Named rig templates. Keys are unqualified; registered as pluginId.key. */
86	  rigTemplates?: Record<string, RigTemplate>;
87	  /** Writ type → rig template name mappings. Keys are unqualified writ type names. */
88	  rigTemplateMappings?: Record<string, string>;
89	}
90	
91	// ── Helpers ────────────────────────────────────────────────────────────
92	
93	/**
94	 * Check whether a value is JSON-serializable.
95	 * Non-serializable yields cause engine failure — the Stacks cannot store them.
96	 */
97	function isJsonSerializable(value: unknown): boolean {
98	  try {
99	    JSON.stringify(value);
100	    return true;
101	  } catch {
102	    return false;
103	  }
104	}
105	
106	/**
107	 * Build the upstream yields map for a rig: all completed engine yields
108	 * keyed by engine id. Passed as context.upstream to the engine's run().
109	 */
110	function buildUpstreamMap(rig: RigDoc): Record<string, unknown> {
111	  const upstream: Record<string, unknown> = {};
112	  for (const engine of rig.engines) {
113	    if (engine.status === 'completed' && engine.yields !== undefined) {
114	      upstream[engine.id] = engine.yields;
115	    }
116	  }
117	  return upstream;
118	}
119	
120	/**
121	 * Find the first pending engine whose entire upstream is completed or skipped.
122	 * Returns null if no runnable engine exists.
123	 */
124	function findRunnableEngine(rig: RigDoc): EngineInstance | null {
125	  for (const engine of rig.engines) {
126	    if (engine.status !== 'pending') continue;
127	    const allUpstreamDone = engine.upstream.every((upstreamId) => {
128	      const dep = rig.engines.find((e) => e.id === upstreamId);
129	      return dep?.status === 'completed' || dep?.status === 'skipped';
130	    });
131	    if (allUpstreamDone) return engine;
132	  }
133	  return null;
134	}
135	
136	/**
137	 * Determine whether a rig should enter the blocked state.
138	 *
139	 * A rig is blocked when:
140	 * - No engine is currently running
141	 * - No engine is runnable (pending with all upstream completed)
142	 * - At least one engine is blocked
143	 */
144	function isRigBlocked(engines: EngineInstance[]): boolean {
145	  const hasRunning = engines.some((e) => e.status === 'running');
146	  if (hasRunning) return false;
147	  const hasBlocked = engines.some((e) => e.status === 'blocked');
148	  if (!hasBlocked) return false;
149	  // Check runnability by constructing a minimal RigDoc-like object
150	  const syntheticRig = { engines } as RigDoc;

