1	/**
2	 * Copilot Session Provider
3	 *
4	 * Apparatus plugin that implements AnimatorSessionProvider using the
5	 * GitHub Models REST API (OpenAI-compatible). The Animator discovers
6	 * this via guild config:
7	 *
8	 *   guild.json["animator"]["sessionProvider"] = "copilot"
9	 *
10	 * Calls the chat completions endpoint, runs an in-process agentic
11	 * tool-call loop when tools are supplied, and supports streaming via SSE.
12	 *
13	 * Key design choice: calls tool handlers directly in-process (no MCP server).
14	 * This is simpler than the claude-code approach since we control the API
15	 * request/response cycle directly.
16	 */
17	
18	import { z } from 'zod';
19	
20	import { guild } from '@shardworks/nexus-core';
21	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
22	import type {
23	  AnimatorSessionProvider,
24	  SessionProviderConfig,
25	  SessionProviderResult,
26	  SessionChunk,
27	} from '@shardworks/animator-apparatus';
28	import type { ResolvedTool } from '@shardworks/tools-apparatus';
29	
30	// ── Config types ────────────────────────────────────────────────────
31	
32	/** Plugin configuration stored at guild.json["copilot"]. */
33	export interface CopilotConfig {
34	  /**
35	   * Chat completions API base endpoint URL.
36	   * Default: 'https://models.inference.ai.azure.com'
37	   */
38	  apiEndpoint?: string;
39	  /**
40	   * Name of the environment variable holding the API bearer token.
41	   * Default: 'GITHUB_TOKEN'
42	   */
43	  tokenEnvVar?: string;
44	  /**
45	   * Maximum number of tool-call rounds in the agentic loop.
46	   * When reached, the session completes with the last available response.
47	   * Default: 50
48	   */
49	  maxToolRounds?: number;
50	}
51	
52	// GuildConfig module augmentation — merged with other augmentations via declaration merging
53	declare module '@shardworks/nexus-core' {
54	  interface GuildConfig {
55	    copilot?: CopilotConfig;
56	  }
57	}
58	
59	// ── Internal types ──────────────────────────────────────────────────
60	
61	/** OpenAI-compatible chat completion message. */
62	interface ChatMessage {
63	  role: 'system' | 'user' | 'assistant' | 'tool';
64	  content: string | null;
65	  tool_calls?: ToolCall[];
66	  tool_call_id?: string;
67	  /** Index signature makes ChatMessage compatible with Record<string, unknown>. */
68	  [key: string]: unknown;
69	}
70	
71	/** OpenAI-compatible tool call from an assistant response. */
72	interface ToolCall {
73	  id: string;
74	  type: 'function';
75	  function: {
76	    name: string;
77	    arguments: string;
78	  };
79	}
80	
81	/** OpenAI-compatible function tool definition for the API request. */
82	interface ToolDef {
83	  type: 'function';
84	  function: {
85	    name: string;
86	    description: string;
87	    parameters: Record<string, unknown>;
88	  };
89	}
90	
91	/** OpenAI-compatible chat completion response (non-streaming). */
92	interface ChatCompletionResponse {
93	  id: string;
94	  choices: Array<{
95	    message: {
96	      role: 'assistant';
97	      content: string | null;
98	      tool_calls?: ToolCall[];
99	    };
100	    finish_reason: string;
101	  }>;
102	  usage?: {
103	    prompt_tokens: number;
104	    completion_tokens: number;
105	  };
106	}
107	
108	/** OpenAI-compatible streaming chunk. */
109	interface ChatCompletionChunk {
110	  id: string;
111	  choices: Array<{
112	    delta: {
113	      role?: string;
114	      content?: string | null;
115	      tool_calls?: Array<{
116	        index: number;
117	        id?: string;
118	        type?: string;
119	        function?: {
120	          name?: string;
121	          arguments?: string;
122	        };
123	      }>;
124	    };
125	    finish_reason: string | null;
126	  }>;
127	  usage?: {
128	    prompt_tokens: number;
129	    completion_tokens: number;
130	  } | null;
131	}
132	
133	/** A single transcript message entry. Matches the TranscriptMessage alias in animator types. */
134	type TranscriptEntry = Record<string, unknown>;
135	
136	/** Accumulated metrics across API calls. */
137	interface SessionAccumulator {
138	  transcript: TranscriptEntry[];
139	  tokenUsage: { inputTokens: number; outputTokens: number };
140	  providerSessionId?: string;
141	}
142	
143	// ── Tool conversion ─────────────────────────────────────────────────
144	
145	/**
146	 * Convert ResolvedTool array to OpenAI function tool format.
147	 *
148	 * Uses z.toJSONSchema() to convert Zod params schema to JSON Schema.
149	 *
150	 * @internal Exported for testing only.
151	 */
152	export function convertTools(tools: ResolvedTool[]): ToolDef[] {
153	  return tools.map((rt) => ({
154	    type: 'function' as const,
155	    function: {
156	      name: rt.definition.name,
157	      description: rt.definition.description,
158	      parameters: z.toJSONSchema(rt.definition.params) as Record<string, unknown>,
159	    },
160	  }));
161	}
162	
163	// ── Output extraction ───────────────────────────────────────────────
164	
165	/**
166	 * Extract the output text from the last assistant message with no tool_calls.
167	 *
168	 * Walks the messages array backwards to find the last assistant message
169	 * that is a "final" response (no pending tool calls).
170	 *
171	 * @internal Exported for testing only.
172	 */
173	export function extractOutput(messages: ChatMessage[]): string | undefined {
174	  for (let i = messages.length - 1; i >= 0; i--) {
175	    const msg = messages[i]!;
176	    if (msg.role !== 'assistant') continue;
177	    if (msg.tool_calls && msg.tool_calls.length > 0) continue;
178	    if (msg.content) return msg.content;
179	  }
180	  return undefined;
181	}
182	
183	// ── SSE parsing ─────────────────────────────────────────────────────
184	
185	/**
186	 * Parse SSE data lines from a buffer, invoking handler for each parsed data value.
187	 * Returns the remaining incomplete buffer.
188	 *
189	 * @internal Exported for testing only.
190	 */
191	export function parseSseLines(buffer: string, handler: (data: string) => void): string {
192	  let idx: number;
193	  while ((idx = buffer.indexOf('\n')) !== -1) {
194	    const line = buffer.slice(0, idx).trim();
195	    buffer = buffer.slice(idx + 1);
196	    if (line.startsWith('data: ')) {
197	      const data = line.slice(6);
198	      if (data === '[DONE]') continue;
199	      handler(data);
200	    }
201	  }
202	  return buffer;
203	}
204	
205	// ── API helpers ─────────────────────────────────────────────────────
206	
207	/**
208	 * Make a non-streaming API call and return the parsed response.
209	 *
210	 * @throws When the HTTP response is not ok, with the status and body.
211	 */
212	async function callApi(
213	  apiEndpoint: string,
214	  token: string,
215	  model: string,
216	  messages: ChatMessage[],
217	  apiTools: ToolDef[],
218	): Promise<ChatCompletionResponse> {
219	  const response = await fetch(`${apiEndpoint}/chat/completions`, {
220	    method: 'POST',
221	    headers: {
222	      'Content-Type': 'application/json',
223	      'Authorization': `Bearer ${token}`,
224	    },
225	    body: JSON.stringify({
226	      model,
227	      messages,
228	      ...(apiTools.length > 0 ? { tools: apiTools } : {}),
229	      stream: false,
230	    }),
231	  });
232	
233	  if (!response.ok) {
234	    const body = await response.text();
235	    throw new Error(`GitHub Models API error: ${response.status} ${body}`);
236	  }
237	
238	  return response.json() as Promise<ChatCompletionResponse>;
239	}
240	
241	/**
242	 * Make a streaming API call, yielding chunks and returning the accumulated assistant message.
243	 *
244	 * Parses SSE events, yields SessionChunk objects in real time, and accumulates
245	 * tool call fragments across delta chunks. Returns the fully assembled assistant
246	 * message and final usage info.
247	 */
248	async function* callApiStreaming(
249	  apiEndpoint: string,
250	  token: string,
251	  model: string,
252	  messages: ChatMessage[],
253	  apiTools: ToolDef[],
254	  acc: SessionAccumulator,
255	): AsyncGenerator<SessionChunk, ChatMessage, undefined> {
256	  const response = await fetch(`${apiEndpoint}/chat/completions`, {
257	    method: 'POST',
258	    headers: {
259	      'Content-Type': 'application/json',
260	      'Authorization': `Bearer ${token}`,
261	    },
262	    body: JSON.stringify({
263	      model,
264	      messages,
265	      ...(apiTools.length > 0 ? { tools: apiTools } : {}),
266	      stream: true,
267	      stream_options: { include_usage: true },
268	    }),
269	  });
270	
271	  if (!response.ok) {
272	    const body = await response.text();
273	    throw new Error(`GitHub Models API error: ${response.status} ${body}`);
274	  }
275	
276	  if (!response.body) {
277	    throw new Error('GitHub Models API error: no response body for streaming request');
278	  }
279	
280	  // Accumulate tool call fragments keyed by index
281	  const toolCallFragments = new Map<number, { id: string; name: string; arguments: string }>();
282	  let textContent = '';
283	  let lastId = '';
284	  let buffer = '';
285	
286	  const reader = response.body.getReader();
287	  const decoder = new TextDecoder();
288	
289	  try {
290	    while (true) {
291	      const { done, value } = await reader.read();
292	      if (done) break;
293	
294	      buffer += decoder.decode(value, { stream: true });
295	
296	      // Process complete SSE lines
297	      const chunks: ChatCompletionChunk[] = [];
298	      buffer = parseSseLines(buffer, (data) => {
299	        try {
300	          chunks.push(JSON.parse(data) as ChatCompletionChunk);
301	        } catch {
302	          // Skip malformed JSON
303	        }
304	      });
305	
306	      for (const chunk of chunks) {
307	        if (chunk.id) lastId = chunk.id;
308	
309	        // Accumulate usage from the final chunk (stream_options.include_usage)
310	        if (chunk.usage) {
311	          acc.tokenUsage.inputTokens += chunk.usage.prompt_tokens;
312	          acc.tokenUsage.outputTokens += chunk.usage.completion_tokens;
313	        }
314	
315	        const choice = chunk.choices[0];
316	        if (!choice) continue;
317	
318	        const delta = choice.delta;
319	
320	        // Text content delta
321	        if (delta.content != null && delta.content !== '') {
322	          textContent += delta.content;
323	          process.stderr.write(delta.content);
324	          yield { type: 'text', text: delta.content };
325	        }
326	
327	        // Tool call deltas — accumulate by index
328	        if (delta.tool_calls) {
329	          for (const tc of delta.tool_calls) {
330	            const existing = toolCallFragments.get(tc.index);
331	            if (!existing) {
332	              // First fragment for this tool call — must have id and name
333	              const frag = {
334	                id: tc.id ?? '',
335	                name: tc.function?.name ?? '',
336	                arguments: tc.function?.arguments ?? '',
337	              };
338	              toolCallFragments.set(tc.index, frag);
339	              if (frag.name) {
340	                yield { type: 'tool_use', tool: frag.name };
341	              }
342	            } else {
343	              // Subsequent fragment — accumulate arguments and fill in missing fields
344	              if (tc.id && !existing.id) existing.id = tc.id;
345	              if (tc.function?.name && !existing.name) {
346	                existing.name = tc.function.name;
347	                yield { type: 'tool_use', tool: existing.name };
348	              }
349	              if (tc.function?.arguments) existing.arguments += tc.function.arguments;
350	            }
351	          }
352	        }
353	      }
354	    }
355	  } finally {
356	    reader.releaseLock();
357	  }
358	
359	  if (lastId) acc.providerSessionId = lastId;
360	
361	  // Reconstruct the full assistant message from accumulated deltas
362	  const toolCalls: ToolCall[] = [];
363	  for (const [, frag] of toolCallFragments) {
364	    toolCalls.push({
365	      id: frag.id,
366	      type: 'function',
367	      function: { name: frag.name, arguments: frag.arguments },
368	    });
369	  }
370	
371	  const assistantMsg: ChatMessage = {
372	    role: 'assistant',
373	    content: textContent || null,
374	    ...(toolCalls.length > 0 ? { tool_calls: toolCalls } : {}),
375	  };
376	
377	  return assistantMsg;
378	}
379	
380	// ── Agentic loop (non-streaming) ────────────────────────────────────
381	
382	/**
383	 * Run the full agentic tool-call loop without streaming.
384	 *
385	 * Makes API calls, executes tools, sends results back, and repeats until
386	 * the model returns a response with no tool_calls or the iteration limit.
387	 */
388	async function runAgenticLoop(
389	  apiEndpoint: string,
390	  token: string,
391	  model: string,
392	  messages: ChatMessage[],
393	  apiTools: ToolDef[],
394	  toolMap: Map<string, ResolvedTool>,
395	  maxRounds: number,
396	  acc: SessionAccumulator,
397	): Promise<void> {
398	  // Make the initial API call
399	  let apiResponse = await callApi(apiEndpoint, token, model, messages, apiTools);
400	
401	  acc.tokenUsage.inputTokens += apiResponse.usage?.prompt_tokens ?? 0;
402	  acc.tokenUsage.outputTokens += apiResponse.usage?.completion_tokens ?? 0;
403	  acc.providerSessionId = apiResponse.id;
404	
405	  const firstChoice = apiResponse.choices[0];
406	  if (!firstChoice) return;
407	
408	  let assistantMsg: ChatMessage = {
409	    role: 'assistant',
410	    content: firstChoice.message.content,
411	    ...(firstChoice.message.tool_calls && firstChoice.message.tool_calls.length > 0
412	      ? { tool_calls: firstChoice.message.tool_calls }
413	      : {}),
414	  };
415	  messages.push(assistantMsg);
416	  acc.transcript.push(assistantMsg as TranscriptEntry);
417	
418	  let round = 0;
419	
420	  while (
421	    assistantMsg.tool_calls &&
422	    assistantMsg.tool_calls.length > 0 &&
423	    round < maxRounds
424	  ) {
425	    round++;
426	
427	    // Execute each tool call and collect results
428	    for (const toolCall of assistantMsg.tool_calls) {
429	      const toolResult = await executeToolCall(toolCall, toolMap);
430	      const toolMsg: ChatMessage = {
431	        role: 'tool',
432	        content: toolResult,
433	        tool_call_id: toolCall.id,
434	      };
435	      messages.push(toolMsg);
436	      acc.transcript.push(toolMsg as TranscriptEntry);
437	    }
438	
439	    // Make the next API call with tool results
440	    apiResponse = await callApi(apiEndpoint, token, model, messages, apiTools);
441	
442	    acc.tokenUsage.inputTokens += apiResponse.usage?.prompt_tokens ?? 0;
443	    acc.tokenUsage.outputTokens += apiResponse.usage?.completion_tokens ?? 0;
444	    acc.providerSessionId = apiResponse.id;
445	
446	    const choice = apiResponse.choices[0];
447	    if (!choice) break;
448	
449	    assistantMsg = {
450	      role: 'assistant',
451	      content: choice.message.content,
452	      ...(choice.message.tool_calls && choice.message.tool_calls.length > 0
453	        ? { tool_calls: choice.message.tool_calls }
454	        : {}),
455	    };
456	    messages.push(assistantMsg);
457	    acc.transcript.push(assistantMsg as TranscriptEntry);
458	  }
459	}
460	
461	/**
462	 * Run the full agentic tool-call loop with streaming.
463	 *
464	 * Yields chunks from each API call, executes tools, sends results back.
465	 */
466	async function* runAgenticLoopStreaming(
467	  apiEndpoint: string,
468	  token: string,
469	  model: string,
470	  messages: ChatMessage[],
471	  apiTools: ToolDef[],
472	  toolMap: Map<string, ResolvedTool>,
473	  maxRounds: number,
474	  acc: SessionAccumulator,
475	): AsyncGenerator<SessionChunk, void, undefined> {
476	  // Make the initial streaming API call
477	  const gen = callApiStreaming(apiEndpoint, token, model, messages, apiTools, acc);
478	  let assistantMsg: ChatMessage;
479	
480	  // Yield chunks from the generator and capture the return value
481	  while (true) {
482	    const result = await gen.next();
483	    if (result.done) {
484	      assistantMsg = result.value;
485	      break;
486	    }
487	    yield result.value;
488	  }
489	
490	  messages.push(assistantMsg);
491	  acc.transcript.push(assistantMsg as TranscriptEntry);
492	
493	  let round = 0;
494	
495	  while (
496	    assistantMsg.tool_calls &&
497	    assistantMsg.tool_calls.length > 0 &&
498	    round < maxRounds
499	  ) {
500	    round++;
501	
502	    // Execute each tool call and collect results
503	    for (const toolCall of assistantMsg.tool_calls) {
504	      const toolResult = await executeToolCall(toolCall, toolMap);
505	      const toolMsg: ChatMessage = {
506	        role: 'tool',
507	        content: toolResult,
508	        tool_call_id: toolCall.id,
509	      };
510	      messages.push(toolMsg);
511	      acc.transcript.push(toolMsg as TranscriptEntry);
512	      yield { type: 'tool_result', tool: toolCall.id };
513	    }
514	
515	    // Make the next streaming API call
516	    const nextGen = callApiStreaming(apiEndpoint, token, model, messages, apiTools, acc);
517	    while (true) {
518	      const result = await nextGen.next();
519	      if (result.done) {
520	        assistantMsg = result.value;
521	        break;
522	      }
523	      yield result.value;
524	    }
525	
526	    messages.push(assistantMsg);
527	    acc.transcript.push(assistantMsg as TranscriptEntry);
528	  }
529	}
530	
531	// ── Tool execution ─────────────────────────────────────────────────
532	
533	/**
534	 * Execute a single tool call and return the result string.
535	 *
536	 * Catches all errors and returns them as error strings rather than
537	 * propagating — the model receives the error and may retry or recover.
538	 */
539	async function executeToolCall(
540	  toolCall: ToolCall,
541	  toolMap: Map<string, ResolvedTool>,
542	): Promise<string> {
543	  const tool = toolMap.get(toolCall.function.name);
544	  if (!tool) {
545	    return `Error: Unknown tool: ${toolCall.function.name}`;
546	  }
547	
548	  try {
549	    const args = JSON.parse(toolCall.function.arguments) as unknown;
550	    const parsed = tool.definition.params.parse(args);
551	    const rawResult = await tool.definition.handler(parsed);
552	    if (typeof rawResult === 'string') return rawResult;
553	    return JSON.stringify(rawResult, null, 2);
554	  } catch (err) {
555	    const message = err instanceof Error ? err.message : String(err);
556	    return `Error: ${message}`;
557	  }
558	}
559	
560	// ── Provider implementation ──────────────────────────────────────────
561	
562	/**
563	 * Create the Copilot session provider apparatus.
564	 *
565	 * The apparatus reads CopilotConfig from guild config at start() time
566	 * and provides an AnimatorSessionProvider backed by the GitHub Models API.
567	 */
568	export function createCopilotProvider(): Plugin {
569	  let config: CopilotConfig = {};
570	
571	  const provider: AnimatorSessionProvider = {
572	    name: 'copilot',
573	
574	    launch(sessionConfig: SessionProviderConfig): {
575	      chunks: AsyncIterable<SessionChunk>;
576	      result: Promise<SessionProviderResult>;
577	    } {
578	      // Resolve config values with defaults
579	      const apiEndpoint = (config.apiEndpoint ?? 'https://models.inference.ai.azure.com').replace(/\/$/, '');
580	      const tokenEnvVar = config.tokenEnvVar ?? 'GITHUB_TOKEN';
581	      const maxRounds = config.maxToolRounds ?? 50;
582	
583	      const acc: SessionAccumulator = {
584	        transcript: [],
585	        tokenUsage: { inputTokens: 0, outputTokens: 0 },
586	      };
587	
588	      // Build initial messages from config
589	      const messages: ChatMessage[] = [];
590	      if (sessionConfig.systemPrompt) {
591	        const systemMsg: ChatMessage = { role: 'system', content: sessionConfig.systemPrompt };
592	        messages.push(systemMsg);
593	        acc.transcript.push(systemMsg as TranscriptEntry);
594	      }
595	      if (sessionConfig.initialPrompt) {
596	        const userMsg: ChatMessage = { role: 'user', content: sessionConfig.initialPrompt };
597	        messages.push(userMsg);
598	        acc.transcript.push(userMsg as TranscriptEntry);
599	      }
600	
601	      // Convert tools
602	      const tools = sessionConfig.tools ?? [];
603	      const apiTools = convertTools(tools);
604	      const toolMap = new Map<string, ResolvedTool>(
605	        tools.map((rt) => [rt.definition.name, rt]),
606	      );
607	
608	      if (sessionConfig.streaming) {
609	        // ── Streaming mode ────────────────────────────────────────────
610	        // Use a push queue + resolve callback to bridge the async generator
611	        // into a pull-based async iterable.
612	
613	        const chunkQueue: SessionChunk[] = [];
614	        let chunkResolve: (() => void) | null = null;
615	        let done = false;
616	        let streamError: Error | null = null;
617	
618	        const result: Promise<SessionProviderResult> = (async () => {
619	          // Validate token
620	          const token = process.env[tokenEnvVar];
621	          if (!token) {
622	            throw new Error(
623	              `Copilot session provider requires a GitHub token. ` +
624	              `Set the ${tokenEnvVar} environment variable.`,
625	            );
626	          }
627	
628	          try {
629	            const gen = runAgenticLoopStreaming(
630	              apiEndpoint, token, sessionConfig.model, messages, apiTools, toolMap, maxRounds, acc,
631	            );
632	
633	            for await (const chunk of gen) {
634	              chunkQueue.push(chunk);
635	              // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-assertion
636	              const notify = chunkResolve as (() => void) | null;
637	              chunkResolve = null;
638	              notify?.();
639	            }
640	
641	            return {
642	              status: 'completed' as const,
643	              exitCode: 0,
644	              providerSessionId: acc.providerSessionId,
645	              tokenUsage: acc.tokenUsage,
646	              costUsd: undefined,
647	              transcript: acc.transcript,
648	              output: extractOutput(messages),
649	            };
650	          } catch (err) {
651	            const message = err instanceof Error ? err.message : String(err);
652	            streamError = err instanceof Error ? err : new Error(message);
653	            return {
654	              status: 'failed' as const,
655	              exitCode: 1,
656	              error: message,
657	              transcript: acc.transcript,
658	              tokenUsage: acc.tokenUsage.inputTokens > 0 ? acc.tokenUsage : undefined,
659	            };
660	          } finally {
661	            done = true;
662	            // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-assertion
663	            const notify = chunkResolve as (() => void) | null;
664	            chunkResolve = null;
665	            notify?.();
666	          }
667	        })();
668	
669	        // Async iterable that drains the chunk queue, pausing between batches
670	        const chunks: AsyncIterable<SessionChunk> = {
671	          [Symbol.asyncIterator]() {
672	            return {
673	              async next(): Promise<IteratorResult<SessionChunk>> {
674	                while (true) {
675	                  if (chunkQueue.length > 0) {
676	                    return { value: chunkQueue.shift()!, done: false };
677	                  }
678	                  if (done || streamError) {
679	                    return { value: undefined as unknown as SessionChunk, done: true };
680	                  }
681	                  await new Promise<void>((resolve) => { chunkResolve = resolve; });
682	                }
683	              },
684	            };
685	          },
686	        };
687	
688	        return { chunks, result };
689	      }
690	
691	      // ── Non-streaming mode ─────────────────────────────────────────
692	      // Chunks iterable is immediately done; all work happens in result.
693	
694	      const emptyChunks: AsyncIterable<SessionChunk> = {
695	        [Symbol.asyncIterator]() {
696	          return {
697	            next(): Promise<IteratorResult<SessionChunk>> {
698	              return Promise.resolve({ value: undefined as unknown as SessionChunk, done: true });
699	            },
700	          };
701	        },
702	      };
703	
704	      const result: Promise<SessionProviderResult> = (async () => {
705	        // Validate token
706	        const token = process.env[tokenEnvVar];
707	        if (!token) {
708	          throw new Error(
709	            `Copilot session provider requires a GitHub token. ` +
710	            `Set the ${tokenEnvVar} environment variable.`,
711	          );
712	        }
713	
714	        try {
715	          await runAgenticLoop(
716	            apiEndpoint, token, sessionConfig.model, messages, apiTools, toolMap, maxRounds, acc,
717	          );
718	
719	          return {
720	            status: 'completed' as const,
721	            exitCode: 0,
722	            providerSessionId: acc.providerSessionId,
723	            tokenUsage: acc.tokenUsage,
724	            costUsd: undefined,
725	            transcript: acc.transcript,
726	            output: extractOutput(messages),
727	          };
728	        } catch (err) {
729	          const message = err instanceof Error ? err.message : String(err);
730	          return {
731	            status: 'failed' as const,
732	            exitCode: 1,
733	            error: message,
734	            transcript: acc.transcript,
735	            tokenUsage: acc.tokenUsage.inputTokens > 0 ? acc.tokenUsage : undefined,
736	          };
737	        }
738	      })();
739	
740	      return { chunks: emptyChunks, result };
741	    },
742	  };
743	
744	  return {
745	    apparatus: {
746	      requires: [],
747	      provides: provider,
748	
749	      start(_ctx: StartupContext): void {
750	        config = guild().guildConfig().copilot ?? {};
751	      },
752	    },
753	  };
754	}
755	
756	export default createCopilotProvider();
757

